function stripCodeFence(str) {
  if (typeof str !== 'string') return str;
  const m = str.match(/```(?:json)?[\s\S]*?({[\s\S]*})/); // JSON 객체 직접 추출
  if (m) return m[1].trim();
  return str.trim();
