  // 이미 achievements 형식이면 그대로
  if (Array.isArray(raw.achievements) && raw.achievements.length > 0) return raw;

  // report[] 또는 기타 배열 필드 사용 시 매핑
  const src = raw.report || raw.results || raw['실적'] || [];
  const achievements = src.map(function(item, i) {
