    var bg = item.background || item.backgroundAndPurpose || item['추진배경'] || item['추진배경및목적'] || '';
    if (item.purpose && !bg.includes(item.purpose)) bg = (bg + '\n\n■ 목적: ' + item.purpose).trim();
    return {
      achievementNumber: item.achievementNumber || item.number || (i + 1),
      type: item.type || item['유형'] || '기타',
      title: item.title || item['제목'] || item.name || '',
      relatedFiles: item.relatedFiles || item.files || [],
      background: bg,
