var html = '<!DOCTYPE html><html lang="ko"><head><meta charset="UTF-8"><title>첨부7 정성보고서 초안</title><style>@media print { .no-print { display: none !important; } body { margin: 0; } .achievement { page-break-inside: avoid; } }body{font-family:"Malgun Gothic",sans-serif;max-width:960px;margin:20px auto;padding:24px;line-height:1.7;color:#222}h1{color:#1a3a5c;border-bottom:3px solid #2980b9;padding-bottom:12px;margin-bottom:6px}.meta{color:#666;font-size:14px;margin-bottom:8px}.print-btn{display:inline-block;background:#2980b9;color:#fff;padding:8px 20px;border-radius:4px;cursor:pointer;border:none;font-size:14px;margin-bottom:20px;font-family:inherit}.achievement{background:#f8f9fa;border-left:5px solid #2980b9;margin:28px 0;padding:20px 24px;border-radius:4px}.ach-header{margin:0 0 10px 0}.ach-num{color:#1a3a5c;font-size:17px;font-weight:bold}.badge{background:#2980b9;color:#fff;padding:3px 12px;border-radius:12px;font-size:12px;margin-left:10px;vertical-align:middle}.files{color:#888;font-size:13px;margin:6px 0 14px 0}.row{display:grid;grid-template-columns:160px 1fr;gap:8px;margin:10px 0;padding:8px 0;border-bottom:1px solid #e9ecef}.row:last-child{border-bottom:none}.lbl{font-weight:bold;color:#555;font-size:14px;padding-top:2px}.val{color:#222;font-size:14px;white-space:pre-wrap}.summary{background:#e8f4fd;border:1px solid #bee3f8;padding:14px 18px;border-radius:4px;margin-bottom:24px;font-size:14px}.footer{color:#aaa;font-size:12px;margin-top:32px;padding-top:12px;border-top:1px solid #eee}</style></head><body>';

html += '<h1>첨부7 정성보고서 초안</h1>';
html += '<div class="meta">실적 ' + achievements.length + '건 | AI 자동 생성 초안 — 반드시 검토 후 사용</div>';
html += '<button class="print-btn no-print" onclick="window.print()">🖨️ PDF로 저장 (인쇄)</button>';

if (data.summary) {
  var summaryIcon = data.summary.startsWith('⚠️') ? '📌 ' : '📌 ';
  html += '<div class="summary">' + summaryIcon + data.summary + '</div>';
}

if (achievements.length === 0) {
  html += '<p style="color:#e74c3c">⚠️ 실적이 없습니다. AI 출력을 확인하세요.</p>';
} else {
  achievements.forEach(function(ach) {
    html += '<div class="achievement">';
    html += '<div class="ach-header">';
    html += '<span class="ach-num">실적' + (ach.achievementNumber || '') + ' ' + (ach.title || '') + '</span>';
    if (ach.type) html += '<span class="badge">' + ach.type + '</span>';
    html += '</div>';
    if (ach.relatedFiles && ach.relatedFiles.length > 0) {
      html += '<div class="files">📎 ' + ach.relatedFiles.join(', ') + '</div>';
    }
    html += '<div class="row"><div class="lbl">추진배경 및 목적</div><div class="val">' + (ach.background || '') + '</div></div>';
    html += '<div class="row"><div class="lbl">추진대상</div><div class="val">' + (ach.target || '') + '</div></div>';
    html += '<div class="row"><div class="lbl">추진내용</div><div class="val">' + (ach.content || '') + '</div></div>';
    html += '<div class="row"><div class="lbl">추진성과(기대효과)</div><div class="val">' + (ach.outcome || '') + '</div></div>';
    html += '</div>';
  });
}

html += '<div class="footer">본 초안은 AI가 생성한 것입니다. 담당자가 반드시 검토·수정 후 활용하시기 바랍니다.</div>';
html += '</body></html>';

return [{
  binary: $input.first().binary,
  json: {
    ...($input.first().json),
    html,
    achievementCount: achievements.length,
    summary: data.summary
  }
}];

const item = $input.first();
const availableKeys = Object.keys(item.json || {});
const html = item.json.html;

if (!html) {
  throw new Error('html 키 없음. 사용 가능한 키: ' + availableKeys.join(', '));
}

const 파일명 = item.json.파일명 || 'report';
const safeFileName = 파일명.replace(/[^a-zA-Z0-9가-힙_-]/g, '_');

return [{
  binary: {
    data: {
      data: Buffer.from(html, 'utf-8').toString('base64'),
      mimeType: 'text/html',
      fileName: `${safeFileName}_분석결과.html`
    }
  },
  json: item.json
}];
